:root {
  --card-bg: #0d1b2a;
  --card-border: #1e3a5f;
  --header-accent: #4fc3f7;
  --title-color: #e8f4fd;
  --mission-label-color: #4fc3f7;
  --badge-bg: #1e3a5f;
  --badge-text: #4fc3f7;
  --badge-border: #2d5a8e;
  --planet-item-bg: #122033;
  --planet-item-border: #1e3a5f;
  --planet-item-featured-bg: #0e2d4a;
  --planet-item-featured-border: #4fc3f7;
  --mercury-color: #b0bec5;
  --venus-color: #ffcc80;
  --mars-color: #ef5350;
  --jupiter-color: #ff8a65;
  --planet-name-color: #cfd8dc;
  --planet-stat-color: #78909c;
  --tag-rocky-bg: #37474f;
  --tag-rocky-text: #b0bec5;
  --tag-hot-bg: #4e342e;
  --tag-hot-text: #ffcc80;
  --tag-gas-bg: #3e2723;
  --tag-gas-text: #ff8a65;
  --stat-value-color: #e8f4fd;
  --stat-label-color: #546e7a;
  --stat-divider-color: #1e3a5f;
  --progress-track: #1e3a5f;
  --progress-fill: #4fc3f7;
  --progress-label-color: #78909c;
  --progress-pct-color: #4fc3f7;
  --btn-bg: #4fc3f7;
  --btn-text: #0d1b2a;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.explorer-card {
  background: var(--card-bg);
  border: 2px solid var(--card-border);
  border-radius: 16px;
  padding: 20px;
  width: 500px;
  max-width: 100%;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.mission-label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--mission-label-color);
  text-transform: uppercase;
}

.card-title {
  font-size: 22px;
  font-weight: 700;
  color: var(--title-color);
  margin: 0;
  line-height: 1.2;
}

.orbit-badge {
  background: var(--badge-bg);
  border: 1px solid var(--badge-border);
  border-radius: 8px;
  padding: 8px 14px;
}

.orbit-number {
  font-size: 13px;
  font-weight: 700;
  color: var(--badge-text);
  letter-spacing: 1px;
}

.planets-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.planet-item {
  background: var(--planet-item-bg);
  border: 1px solid var(--planet-item-border);
  border-radius: 10px;
  padding: 12px 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.planet-item.featured {
  background: var(--planet-item-featured-bg);
  border-color: var(--planet-item-featured-border);
}

.planet-visual {
  width: 36px;
  height: 36px;
  border-radius: 50%;
}

.planet-visual.mercury {
  background: var(--mercury-color);
}

.planet-visual.venus {
  background: var(--venus-color);
}

.planet-visual.mars {
  background: var(--mars-color);
}

.planet-visual.jupiter {
  background: var(--jupiter-color);
}

.planet-info {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.planet-name {
  font-size: 12px;
  font-weight: 600;
  color: var(--planet-name-color);
}

.planet-stat {
  font-size: 10px;
  color: var(--planet-stat-color);
}

.planet-tag {
  font-size: 9px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 4px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.planet-tag.rocky {
  background: var(--tag-rocky-bg);
  color: var(--tag-rocky-text);
}

.planet-tag.hot {
  background: var(--tag-hot-bg);
  color: var(--tag-hot-text);
}

.planet-tag.gas {
  background: var(--tag-gas-bg);
  color: var(--tag-gas-text);
}

.stats-row {
  display: flex;
  align-items: center;
  background: var(--planet-item-bg);
  border: 1px solid var(--planet-item-border);
  border-radius: 10px;
  padding: 12px 0;
}

.stat-block {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
}

.stat-value {
  font-size: 18px;
  font-weight: 700;
  color: var(--stat-value-color);
  line-height: 1;
}

.stat-label {
  font-size: 10px;
  color: var(--stat-label-color);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.stat-divider {
  width: 1px;
  height: 32px;
  background: var(--stat-divider-color);
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.progress-section {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
}

.progress-label {
  font-size: 11px;
  color: var(--progress-label-color);
  white-space: nowrap;
}

.progress-bar {
  flex: 1;
  height: 6px;
  background: var(--progress-track);
  border-radius: 3px;
  overflow: hidden;
}

.progress-fill {
  width: 74%;
  height: 100%;
  background: var(--progress-fill);
  border-radius: 3px;
}

.progress-pct {
  font-size: 12px;
  font-weight: 700;
  color: var(--progress-pct-color);
}

.launch-btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: 8px;
  padding: 9px 18px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  white-space: nowrap;
}
